import{_ as t,o as a,c as i,a2 as r}from"./chunks/framework.D5wUhsuj.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md"}'),n={name:"guide/introduction.md"};function d(o,e,s,c,l,u){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>AidiPanel is a lightweight server control panel for Ubuntu and Debian VPS instances. It installs and manages an Nginx, PHP-FPM, MariaDB/MySQL, Redis, and Certbot stack through a web panel and CLI.</p><h2 id="design-principles" tabindex="-1">Design principles <a class="header-anchor" href="#design-principles" aria-label="Permalink to &quot;Design principles&quot;">​</a></h2><ul><li><strong>FastCGI Cache stays in Nginx.</strong> Cache hits avoid PHP entirely, with per-site controls and WordPress-aware bypass rules.</li><li><strong>Isolation is the default.</strong> Every site receives a dedicated no-login Linux user and PHP-FPM pool.</li><li><strong>The panel has its own runtime.</strong> The UI runs as the dedicated <code>aidipanel</code> account through <code>/run/aidipanel-fpm.sock</code>; Nginx continues to run as <code>www-data</code>.</li><li><strong>Operations remain inspectable.</strong> The <code>aidipanel</code> CLI covers sites, files, databases, cache, PHP, SSL, backups, SFTP, security, users, and diagnostics.</li><li><strong>Security-sensitive changes are narrow.</strong> The web panel reaches privileged operations through one root-owned wrapper instead of running the application as root.</li></ul><h2 id="included-in-v1-2-0" tabindex="-1">Included in v1.2.0 <a class="header-anchor" href="#included-in-v1-2-0" aria-label="Permalink to &quot;Included in v1.2.0&quot;">​</a></h2><p>AidiPanel provides site creation and guarded deletion, a file manager, isolated phpMyAdmin access, cron management, PHP tuning, local and scheduled S3-compatible backups, jailed SFTP, Basic Auth, IP blocking, Cloudflare-only origin access, panel roles, two-factor authentication, and server diagnostics.</p><p>It is intended for developers, WordPress builders, agencies, VPS operators, and self-hosters managing PHP applications. It is not a billing, mail-hosting, DNS-authority, reseller, or multi-node platform.</p><h2 id="stack-at-a-glance" tabindex="-1">Stack at a glance <a class="header-anchor" href="#stack-at-a-glance" aria-label="Permalink to &quot;Stack at a glance&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Layer</th><th>Software</th><th>Role</th></tr></thead><tbody><tr><td>Web server</td><td>Nginx</td><td>Static files, TLS, reverse proxying, and FastCGI Cache</td></tr><tr><td>Site runtime</td><td>PHP-FPM</td><td>Dedicated pool per PHP site</td></tr><tr><td>Panel runtime</td><td>PHP-FPM</td><td>Dedicated <code>aidipanel</code> service and socket</td></tr><tr><td>Database</td><td>MariaDB or MySQL</td><td>Selectable during installation</td></tr><tr><td>Object cache</td><td>Redis</td><td>Optional per-site WordPress object caching</td></tr><tr><td>TLS</td><td>Certbot</td><td>Let&#39;s Encrypt certificates and renewal</td></tr><tr><td>Security</td><td>UFW + Fail2ban</td><td>Firewall and brute-force protection</td></tr><tr><td>Management</td><td>Web panel + <code>aidipanel</code></td><td>Browser and SSH workflows</td></tr></tbody></table><h2 id="where-to-go-next" tabindex="-1">Where to go next <a class="header-anchor" href="#where-to-go-next" aria-label="Permalink to &quot;Where to go next&quot;">​</a></h2><div class="ap-cards"><p><strong><a href="/docs/guide/installation">Installation →</a></strong> Prepare a fresh server and install the latest stable release.</p><p><strong><a href="/docs/guide/quick-start">Quick Start →</a></strong> Create your first isolated site and issue its certificate.</p><p><strong><a href="/docs/guide/architecture">Architecture →</a></strong> Understand users, services, sockets, privilege boundaries, and request flow.</p></div>',11)])])}const g=t(n,[["render",d]]);export{p as __pageData,g as default};
